$pref = Get-MpPreference; Write-Host 'Real-time Protection: ' -NoNewline; if ($pref.DisableRealtimeMonitoring) { Write-Host 'DISABLED' -ForegroundColor Red } else { Write-Host 'ENABLED' -ForegroundColor Green }; Write-Host 'Behavior Monitoring: ' -NoNewline; if ($pref.DisableBehaviorMonitoring) { Write-Host 'DISABLED' -ForegroundColor Red } else { Write-Host 'ENABLED' -ForegroundColor Green }; Write-Host 'Cloud Protection: ' -NoNewline; if ($pref.MAPSReporting -eq 0) { Write-Host 'DISABLED' -ForegroundColor Red } else { Write-Host 'ENABLED' -ForegroundColor Green }; Write-Host 'Sample Submission: ' -NoNewline; if ($pref.SubmitSamplesConsent -eq 2) { Write-Host 'DISABLED' -ForegroundColor Red } else { Write-Host 'ENABLED' -ForegroundColor Green }
